SELECT upstream_metric_id
FROM bi_metric_lineage
WHERE downstream_metric_id = #{metricId}

SELECT downstream_metric_id
FROM bi_metric_lineage
WHERE upstream_metric_id = #{metricId}

WITH RECURSIVE lineage_cte AS ( -- 起始节点 SELECT upstream_metric_id, downstream_metric_id, 1 AS depth FROM bi_metric_lineage WHERE downstream_metric_id = #{metricId}
UNION ALL
-- 递归查询上游 SELECT ml.upstream_metric_id, ml.downstream_metric_id, cte.depth + 1 FROM bi_metric_lineage ml INNER JOIN lineage_cte cte ON ml.downstream_metric_id = cte.upstream_metric_id WHERE cte.depth < 10 ) SELECT COUNT(*) AS count FROM lineage_cte WHERE upstream_metric_id = #{metricId}

